static GMutex lock;
static GHashTable *loops;        /* key: (start<<1)^end -> LoopEdge* */
static GArray *vcpu_state;       /* indexed by cpu_index */
static guint64 limit = 50;       /* max rows printed */
static guint64 min_iters = 1;    /* rows with count < min_iters are dropped */
static guint64 optimize_rvv = 0; /* 1: drop loops without RVV instructions */

typedef struct {
    uint64_t start_pc;           /* loop header (target of backward branch) */
    uint64_t end_pc;             /* tail: last insn pc of preceding TB */
    uint64_t count;              /* iterations observed */
    bool     has_rvv;            /* loop body contains an RVV instruction */
} LoopEdge;

typedef struct {
    uint64_t last_tail_pc;       /* PC of last insn of previously executed TB */
    bool     valid;
    bool     saw_rvv;            /* RVV insn observed since last loop edge */
} VCPUState;

typedef struct {
    uint64_t tb_start;
    uint64_t tb_last_insn_pc;
    bool     has_rvv;
} TBInfo;

/*
 * Returns true if @insn (32-bit RISC-V encoding, little-endian integer
 * value) is an RVV instruction:
 *   - OP-V (opcode 1010111): all vector arithmetic + vsetvl{i}.
 *   - LOAD-FP (0000111) / STORE-FP (0100111) with funct3 in {0,5,6,7}:
 *     vector unit-stride/strided/indexed loads/stores (SEW=8/16/32/64).
 *     funct3 = 010/011/100 are scalar FLW/FLD/FLQ - excluded.
 * Compressed (16-bit) insns are not RVV in the baseline V 1.0 spec.
 */
static bool insn_is_rvv(uint32_t insn)
{
    uint32_t opcode = insn & 0x7f;
    uint32_t funct3 = (insn >> 12) & 0x7;

    if (opcode == 0x57) {
        return true;
    }
    if (opcode == 0x07 || opcode == 0x27) {
        return funct3 == 0 || funct3 == 5 || funct3 == 6 || funct3 == 7;
    }
    return false;
}

